import sys

def main():
    data = sys.stdin.buffer.read().split()
    pos = 0
    t = int(data[pos]); pos += 1
    out = []
    for _ in range(t):
        n, k = int(data[pos]), int(data[pos + 1]); pos += 2
        p = sorted(int(x) for x in data[pos:pos + n]); pos += n

        def feasible(d):
            cnt = 1
            last = p[0]
            for x in p:
                if x - last >= d:
                    cnt += 1
                    last = x
                    if cnt >= k:
                        return True
            return cnt >= k

        lo, hi = 1, p[-1] - p[0]
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1
        out.append(str(lo))
    sys.stdout.write("\n".join(out) + "\n")

main()
